Flujo de calor latente preliminar


Code
df_le &lt;- diario |&gt;
  filter(!is.na(fecha), !is.na(LE_medio)) |&gt;
  mutate(
    tooltip = paste0(
      "Parcela: ", grupo,
      "&lt;br&gt;Fecha: ", fecha,
      "&lt;br&gt;LE: ", round(LE_medio, 2), " W m⁻²"
    )
  )

if (hay_datos(df_le)) {
  p_le &lt;- ggplot(df_le, aes(x = fecha, y = LE_medio, color = grupo, group = grupo)) +
    geom_line(linewidth = 0.75, alpha = 0.9) +
    labs(x = NULL, y = "LE medio diario (W m⁻²)", color = "Parcela") +
    theme_minimal(base_size = 13)

  p_le
} else {
  htmltools::HTML("&lt;div class='puma-card'&gt;Aún no hay datos suficientes de LE para graficar.&lt;/div&gt;")
}




