Figure 2

Componentes del balance energético


Code
componentes &lt;- diario |&gt;
  select(grupo, fecha, LE_medio, H_medio, Rn_medio, G_medio) |&gt;
  pivot_longer(c(LE_medio, H_medio, Rn_medio, G_medio),
               names_to = "Componente", values_to = "Valor") |&gt;
  filter(!is.na(fecha), !is.na(Valor)) |&gt;
  mutate(Componente = recode(Componente,
                             LE_medio = "LE",
                             H_medio  = "H",
                             Rn_medio = "Rn",
                             G_medio  = "G"))

if (hay_datos(componentes)) {
  p_comp &lt;- ggplot(componentes, aes(x = fecha, y = Valor, color = Componente, group = Componente)) +
    geom_line(linewidth = 0.55, alpha = 0.85) +
    facet_wrap(~grupo, scales = "free_y") +
    labs(x = NULL, y = "Flujo medio diario (W m⁻²)", color = NULL) +
    theme_minimal(base_size = 13)

  p_comp
} else {
  htmltools::HTML("&lt;div class='puma-card'&gt;Aún no hay datos suficientes para graficar los componentes del balance energético.&lt;/div&gt;")
}








