temp_long &lt;- diario |&gt;
  select(grupo, fecha, temp_aire, temp_superficie) |&gt;
  pivot_longer(c(temp_aire, temp_superficie), names_to = "variable", values_to = "valor") |&gt;
  filter(!is.na(fecha), !is.na(valor)) |&gt;
  mutate(variable = recode(variable,
                           temp_aire = "Temperatura del aire",
                           temp_superficie = "Temperatura superficial"))

if (hay_datos(temp_long)) {
  p_temp &lt;- ggplot(temp_long, aes(x = fecha, y = valor, color = variable, group = variable)) +
    geom_line(linewidth = 0.6, alpha = 0.85) +
    facet_wrap(~grupo, scales = "free_y") +
    labs(x = NULL, y = "Temperatura (°C)", color = NULL) +
    theme_minimal(base_size = 13)

  p_temp
} else {
  htmltools::HTML("&lt;div class='puma-card'&gt;Aún no hay datos suficientes de temperatura para graficar.&lt;/div&gt;")
}








