Figure 5

Precipitación y ETo


Code
agua &lt;- diario |&gt;
  group_by(fecha) |&gt;
  summarise(
    lluvia = suppressWarnings(max(lluvia, na.rm = TRUE)),
    ETo = suppressWarnings(mean(ETo, na.rm = TRUE)),
    .groups = "drop"
  ) |&gt;
  mutate(across(where(is.numeric), ~ ifelse(is.infinite(.x) | is.nan(.x), NA_real_, .x))) |&gt;
  pivot_longer(c(lluvia, ETo), names_to = "variable", values_to = "valor") |&gt;
  filter(!is.na(fecha), !is.na(valor)) |&gt;
  mutate(variable = recode(variable,
                           lluvia = "Precipitación",
                           ETo = "ETo"))

if (hay_datos(agua)) {
  p_agua &lt;- ggplot(agua, aes(x = fecha, y = valor, color = variable, group = variable)) +
    geom_line(linewidth = 0.75) +
    labs(x = NULL, y = "mm día⁻¹", color = NULL) +
    theme_minimal(base_size = 13)

  p_agua
} else {
  htmltools::HTML("&lt;div class='puma-card'&gt;Aún no hay datos suficientes de precipitación o ETo para graficar.&lt;/div&gt;")
}








